#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

#define IDX2(row, col, ld) ((row) * (ld) + (col))

__kernel void
lud_diagonal(__global float *m,
             __local float *shadow,
             const int matrix_dim,
             const int offset)
{
    const int tx = (int)get_local_id(0);
    int i, j;
    int array_offset = offset * matrix_dim + offset;

    for (i = 0; i < BLOCK_SIZE; i++) {
        shadow[IDX2(i, tx, BLOCK_SIZE)] = m[array_offset + tx];
        array_offset += matrix_dim;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    for (i = 0; i < BLOCK_SIZE - 1; i++) {
        if (tx > i) {
            for (j = 0; j < i; j++) {
                shadow[IDX2(tx, i, BLOCK_SIZE)] -=
                    shadow[IDX2(tx, j, BLOCK_SIZE)] * shadow[IDX2(j, i, BLOCK_SIZE)];
            }
            shadow[IDX2(tx, i, BLOCK_SIZE)] /= shadow[IDX2(i, i, BLOCK_SIZE)];
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        if (tx > i) {
            for (j = 0; j < i + 1; j++) {
                shadow[IDX2(i + 1, tx, BLOCK_SIZE)] -=
                    shadow[IDX2(i + 1, j, BLOCK_SIZE)] * shadow[IDX2(j, tx, BLOCK_SIZE)];
            }
        }

        barrier(CLK_LOCAL_MEM_FENCE);
    }

    array_offset = (offset + 1) * matrix_dim + offset;
    for (i = 1; i < BLOCK_SIZE; i++) {
        m[array_offset + tx] = shadow[IDX2(i, tx, BLOCK_SIZE)];
        array_offset += matrix_dim;
    }
}

__kernel void
lud_perimeter(__global float *m,
              __local float *dia,
              __local float *peri_row,
              __local float *peri_col,
              const int matrix_dim,
              const int offset)
{
    const int tx = (int)get_local_id(0);
    const int bx = (int)get_group_id(0);
    int i, j, array_offset, idx;

    if (tx < BLOCK_SIZE) {
        idx = tx;

        array_offset = offset * matrix_dim + offset;
        for (i = 0; i < BLOCK_SIZE / 2; i++) {
            dia[IDX2(i, idx, BLOCK_SIZE)] = m[array_offset + idx];
            array_offset += matrix_dim;
        }

        array_offset = offset * matrix_dim + offset;
        for (i = 0; i < BLOCK_SIZE; i++) {
            peri_row[IDX2(i, idx, BLOCK_SIZE)] =
                m[array_offset + (bx + 1) * BLOCK_SIZE + idx];
            array_offset += matrix_dim;
        }
    } else {
        idx = tx - BLOCK_SIZE;

        array_offset = (offset + BLOCK_SIZE / 2) * matrix_dim + offset;
        for (i = BLOCK_SIZE / 2; i < BLOCK_SIZE; i++) {
            dia[IDX2(i, idx, BLOCK_SIZE)] = m[array_offset + idx];
            array_offset += matrix_dim;
        }

        array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
        for (i = 0; i < BLOCK_SIZE; i++) {
            peri_col[IDX2(i, idx, BLOCK_SIZE)] = m[array_offset + idx];
            array_offset += matrix_dim;
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    if (tx < BLOCK_SIZE) {
        idx = tx;
        for (i = 1; i < BLOCK_SIZE; i++) {
            for (j = 0; j < i; j++) {
                peri_row[IDX2(i, idx, BLOCK_SIZE)] -=
                    dia[IDX2(i, j, BLOCK_SIZE)] * peri_row[IDX2(j, idx, BLOCK_SIZE)];
            }
        }
    } else {
        idx = tx - BLOCK_SIZE;
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < i; j++) {
                peri_col[IDX2(idx, i, BLOCK_SIZE)] -=
                    peri_col[IDX2(idx, j, BLOCK_SIZE)] * dia[IDX2(j, i, BLOCK_SIZE)];
            }
            peri_col[IDX2(idx, i, BLOCK_SIZE)] /= dia[IDX2(i, i, BLOCK_SIZE)];
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    if (tx < BLOCK_SIZE) {
        idx = tx;
        array_offset = (offset + 1) * matrix_dim + offset;
        for (i = 1; i < BLOCK_SIZE; i++) {
            m[array_offset + (bx + 1) * BLOCK_SIZE + idx] =
                peri_row[IDX2(i, idx, BLOCK_SIZE)];
            array_offset += matrix_dim;
        }
    } else {
        idx = tx - BLOCK_SIZE;
        array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
        for (i = 0; i < BLOCK_SIZE; i++) {
            m[array_offset + idx] = peri_col[IDX2(i, idx, BLOCK_SIZE)];
            array_offset += matrix_dim;
        }
    }
}

__kernel void
lud_internal(__global float *m,
             __local float *peri_row,
             __local float *peri_col,
             const int matrix_dim,
             const int offset)
{
    const int tx = (int)get_local_id(0);
    const int ty = (int)get_local_id(1);
    const int bx = (int)get_group_id(0);
    const int by = (int)get_group_id(1);

    int i;
    float sum = 0.0f;

    const int global_row_id = offset + (by + 1) * BLOCK_SIZE;
    const int global_col_id = offset + (bx + 1) * BLOCK_SIZE;

    peri_row[IDX2(ty, tx, BLOCK_SIZE)] =
        m[(offset + ty) * matrix_dim + global_col_id + tx];
    peri_col[IDX2(ty, tx, BLOCK_SIZE)] =
        m[(global_row_id + ty) * matrix_dim + offset + tx];

    barrier(CLK_LOCAL_MEM_FENCE);

    for (i = 0; i < BLOCK_SIZE; i++) {
        sum += peri_col[IDX2(ty, i, BLOCK_SIZE)] * peri_row[IDX2(i, tx, BLOCK_SIZE)];
    }

    m[(global_row_id + ty) * matrix_dim + global_col_id + tx] -= sum;
}
